// release-please-config.json
{
  "$schema": "https://raw.githubusercontent.com/googleapis/release-please/main/schemas/config.json",
  "release-type": "python",
  "packages": {
    ".": {
      "release-type": "python",
      "changelog-sections": [
        { "type": "safety",  "section": "Safety",         "hidden": false },
        { "type": "feat",    "section": "Features",       "hidden": false },
        { "type": "fix",     "section": "Bug Fixes",      "hidden": false },
        { "type": "prompt",  "section": "Prompt Changes", "hidden": false },
        { "type": "eval",    "section": "Eval Metrics",   "hidden": false },
        { "type": "model",   "section": "Model Version",  "hidden": false },
        { "type": "docs",    "section": "Docs",           "hidden": false },
        { "type": "chore",   "section": "Miscellaneous",  "hidden": true  },
        { "type": "refactor","section": "Miscellaneous",  "hidden": true  },
        { "type": "test",    "section": "Miscellaneous",  "hidden": true  }
      ],
      "bump-minor-pre-major": true,
      "bump-patch-for-minor-pre-major": true,
      "extra-files": [
        "pyproject.toml",
        "src/ai_service/__version__.py"
      ]
    }
  }
}
